defmodule SessionManager.Plug do
  @moduledoc """
  Plug for integrating SessionManager with Phoenix/Plug pipelines.
  """

  import Plug.Conn
  @behaviour Plug

  @impl true
  def init(opts), do: opts

  @impl true
  def call(conn, _opts) do
    cookie_name = SessionManager.cookie_name()

    conn
    |> fetch_cookies()
    |> load_session(cookie_name)
    |> register_before_send(&save_session(&1, cookie_name))
  end

  defp load_session(conn, cookie_name) do
    case Map.get(conn.cookies, cookie_name) do
      nil ->
        session = SessionManager.new_session(%{
          ip_address: to_string(:inet.ntoa(conn.remote_ip))
        })
        assign(conn, :session, session)

      cookie_value ->
        case SessionManager.deserialize(cookie_value) do
          {:ok, session} ->
            # Renew session on each request
            session = SessionManager.renew(session)
            assign(conn, :session, session)

          {:error, _reason} ->
            # Invalid or expired session, create a new one
            session = SessionManager.new_session(%{
              ip_address: to_string(:inet.ntoa(conn.remote_ip))
            })
            assign(conn, :session, session)
        end
    end
  end

  defp save_session(conn, cookie_name) do
    case conn.assigns[:session] do
      %SessionManager.Session{} = session ->
        # Clear flash after sending response
        session = SessionManager.clear_flash(session)
        serialized = SessionManager.serialize(session)
        put_resp_cookie(conn, cookie_name, serialized, SessionManager.cookie_options())

      _ ->
        conn
    end
  end
end

